rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    function isSignedIn() {
      return request.auth != null;
    }

    // CLIENTS: Public read, only owner can write
    match /clients/{userId} {
      allow read: if true;
      allow create, update, delete: if isSignedIn() && request.auth.uid == userId;
    }

    // TECHNICIANS: Public read, only owner can write
    match /technicians/{userId} {
      allow read: if true;
      allow create, update, delete: if isSignedIn() && request.auth.uid == userId;
    }

    // SERVICE REQUESTS: Authenticated users can read/list, only client can create/update/delete
    match /serviceRequests/{requestId} {
      allow get, list: if isSignedIn();
      allow create: if isSignedIn() && request.resource.data.clientId == request.auth.uid;
      allow update, delete: if isSignedIn() && resource.data.clientId == request.auth.uid;
    }

    // PRODUCTS: Public read, write restricted to admin
    match /products/{productId} {
      allow read: if true;
      // Replace 'YOUR_ADMIN_UID' with the actual UID of the administrator
      allow write: if isSignedIn() && request.auth.uid == 'YOUR_ADMIN_UID';
    }

    // ORDERS: Users can create and read their own orders
    match /orders/{orderId} {
        allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
        allow read: if isSignedIn() && resource.data.userId == request.auth.uid;
        allow update, delete: if false; // Orders are final
    }

    // RATINGS: Authenticated users can create, public can read
    match /ratings/{ratingId} {
        allow read: if true;
        allow create: if isSignedIn() && request.resource.data.clientId == request.auth.uid;
    }
  }
}


import type { Metadata } from "next";
import { Inter } from "next/font/google";
import "./globals.css";
import { cn } from "@/lib/utils";
import { Toaster } from "@/components/ui/toaster";
import { FirebaseProvider } from "@/lib/firebase";
import Script from "next/script";
import Header from "@/components/Header";
import Footer from "@/components/Footer";
import StickyFooterAd from "@/components/StickyFooterAd";

const inter = Inter({ subsets: ["latin"] });

export const metadata: Metadata = {
  title: "ProBénin - Le Pro qu'il vous faut, à côté de chez vous.",
  description: "Mise en relation intelligente entre clients ayant des pannes domestiques et techniciens qualifiés au Bénin.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="fr">
      <head>
        <Script
          async
          src={`https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-6115906924297706`}
          crossOrigin="anonymous"
          strategy="lazyOnload"
        />
      </head>
      <body className={cn(inter.className, "min-h-screen bg-background font-sans antialiased pb-24")}>
        <FirebaseProvider>
          <Header />
          <main className="flex flex-col items-center">
            {children}
          </main>
          <Footer />
          <Toaster />
          <StickyFooterAd />
        </FirebaseProvider>
      </body>
    </html>
  );
}


