import { GoogleGenerativeAI, HarmCategory, HarmBlockThreshold } from "@google/generative-ai";
import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

const generationConfig = {
    temperature: 0.9,
    topK: 1,
    topP: 1,
    maxOutputTokens: 2048,
};

const safetySettings = [
    { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
    { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
    { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
    { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
];

const diagnosisRequestSchema = z.object({
    history: z.array(z.object({
        role: z.string(),
        parts: z.array(z.object({
            text: z.string()
        }))
    }))
});

export async function POST(req: NextRequest) {
    if (!process.env.GEMINI_API_KEY) {
        return NextResponse.json({ error: "API key is not configured" }, { status: 500 });
    }

    try {
        const body = await req.json();
        const validation = diagnosisRequestSchema.safeParse(body);

        if (!validation.success) {
            return NextResponse.json({ error: "Invalid request body", details: validation.error.errors }, { status: 400 });
        }

        const { history } = validation.data;

        const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
        const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash", safetySettings });

        const parts = [
            { text: `System instruction: Tu es un assistant intelligent pour l'application ProBénin. Ton rôle est de diagnostiquer des pannes domestiques au Bénin (Cotonou, Calavi, etc.).
- Interroge le client en français simple, avec des expressions béninoises ("Yako", "Ça va aller", "On va gérer ça").
- Ton objectif est de comprendre le problème pour le transmettre à un technicien.
- NE JAMAIS DONNER DE PRIX. Si on te demande, réponds "Le prix sera fixé par le technicien sur place, le service de mise en relation est 100% gratuit."
- NE JAMAIS DEMANDER D'ARGENT (Mobile Money, etc.). Le service est gratuit.
- Demande le quartier du client ("Dans quel quartier de Cotonou êtes-vous ?").
- Avant de conclure, demande le numéro WhatsApp du client: "Pour faciliter la communication, pouvez-vous me donner votre numéro WhatsApp svp ?".
- Sois bref et direct. Pose une seule question à la fois.
- Conclus toujours par une phrase qui rassure et indique que le diagnostic est terminé et qu'on va trouver un pro pour lui. Par exemple: "Merci pour les détails. C'est parfait. On va trouver un technicien compétent pour votre souci."
` },
        ];

        const result = await model.generateContent({
            contents: [...parts, ...history],
            generationConfig,
        });

        const response = result.response;
        const responseText = response.text();

        return NextResponse.json({ response: responseText });

    } catch (e: any) {
        console.error("Error in diagnosis API:", e);
        const errorMessage = e.message || "An unknown error occurred";
        return NextResponse.json({ 
            error: "Oups, l'assistant IA a un souci technique.",
            details: errorMessage,
            // Fallback response so the user flow is not blocked
            response: "Merci pour votre message. Veuillez décrire votre problème et indiquer votre quartier et numéro WhatsApp. Un technicien vous contactera." 
        }, { status: 500 });
    }
}


'use client'
import {initializeApp, getApps, getApp, FirebaseApp} from 'firebase/app';
import {getAuth, Auth} from 'firebase/auth';
import {getFirestore, Firestore} from 'firebase/firestore';
import React, {createContext, useContext} from 'react';

// IMPORTANT: Replace with your Firebase project's configuration
const firebaseConfig = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY,
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID,
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID,
};

// Initialize Firebase
let app: FirebaseApp;
if (!getApps().length) {
  app = initializeApp(firebaseConfig);
} else {
  app = getApp();
}

const auth = getAuth(app);
const db = getFirestore(app);

// Context for providing Firebase services to components
const FirebaseContext = createContext<{
  app: FirebaseApp;
  auth: Auth;
  db: Firestore;
} | null>(null);

export const FirebaseProvider: React.FC<{children: React.ReactNode}> = ({children}) => {
  return (
    <FirebaseContext.Provider value={{app, auth, db}}>
      {children}
    </FirebaseContext.Provider>
  );
};

// Hook to use Firebase services
export const useFirebase = () => {
  const context = useContext(FirebaseContext);
  if (!context) {
    throw new Error('useFirebase must be used within a FirebaseProvider');
  }
  return context;
};

export { app, auth, db };


import { useCollection as useFirebaseCollection } from 'react-firebase-hooks/firestore';
import { collection, query, CollectionReference, Query } from 'firebase/firestore';
import { useFirebase } from './firebase';

export const useCollection = (path: string, q?: (ref: CollectionReference) => Query) => {
    const { db } = useFirebase();
    const ref = collection(db, path);
    const finalQuery = q ? q(ref) : ref;
    return useFirebaseCollection(finalQuery);
}


import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
